function elapsedDuration(issue: any): { label: string; color: string } {
  if (!issue.created_at) return { label: '-', color: '' }
  const hours = (Date.now() - new Date(issue.created_at).getTime()) / 3600000
  if (hours < 24) return { label: `${Math.max(1, Math.round(hours))}小时`, color: '#22c55e' }
  const days = Math.round(hours / 24)
  if (days <= 1) return { label: '1天', color: '#22c55e' }
  if (days <= 2) return { label: `${days}天`, color: '#eab308' }
  return { label: `${days}天`, color: '#ef4444' }
}

function durationProgress(issue: any): { label: string; color: string } {
  if (!issue.created_at || !issue.estimated_completion) return { label: '-', color: '' }
  const start = new Date(issue.created_at).getTime()
  const end = new Date(issue.estimated_completion).getTime()
  const now = Date.now()
  const total = end - start
  if (total <= 0) return { label: '100%', color: '#ef4444' }
  const pct = Math.round(((now - start) / total) * 100)
  const color = pct <= 60 ? '#22c55e' : pct <= 90 ? '#eab308' : '#ef4444'
  return { label: `${pct}%`, color }
}

